import React, { useMemo } from "react";

// Import your MP4s (adjust paths/names to match your files)
// Desktop
import clearDayDesktop from "../assets/overlays/clearday.mp4";
import clearNightDesktop from "../assets/overlays/clearnight.mp4";
import cloudyDayDesktop from "../assets/overlays/cloudyday.mp4";
import cloudyNightDesktop from "../assets/overlays/cloudynight.mp4";
import rainDayDesktop from "../assets/overlays/rainday.mp4";
import rainNightDesktop from "../assets/overlays/rainnight.mp4";
import snowDayDesktop from "../assets/overlays/snowday.mp4";
import snowNightDesktop from "../assets/overlays/snownight.mp4";
import thunderDayDesktop from "../assets/overlays/thunderstormday.mp4";
import thunderNightDesktop from "../assets/overlays/thunderstormnight.mp4";
import fogDayDesktop from "../assets/overlays/fogday.mp4";
import fogNightDesktop from "../assets/overlays/fognight.mp4";

// Mobile (if you have distinct mobile clips; otherwise map these to desktop clips)
import clearDayMobile from "../assets/overlays/cleardaymobile.mp4";
import clearNightMobile from "../assets/overlays/clearnightmobile.mp4";
import cloudyDayMobile from "../assets/overlays/cloudydaymobile.mp4";
import cloudyNightMobile from "../assets/overlays/cloudynightmobile.mp4";
import rainDayMobile from "../assets/overlays/raindaymobile.mp4";
import rainNightMobile from "../assets/overlays/rainnightmobile.mp4";
import snowDayMobile from "../assets/overlays/snowdaymobile.mp4";
import snowNightMobile from "../assets/overlays/snownightmobile.mp4";
import thunderDayMobile from "../assets/overlays/thunderstormdaymobile.mp4";
import thunderNightMobile from "../assets/overlays/thunderstormnightmobile.mp4";
import fogDayMobile from "../assets/overlays/fogdaymobile.mp4";
import fogNightMobile from "../assets/overlays/fognightmobile.mp4";

/**
 * Normalize any weather "condition" input into a canonical key.
 * Accepts:
 *  - string: "Rain", "Clouds", "Clear", ...
 *  - object: { main: "Rain", description: "light rain", ... } (like OpenWeather)
 */
function normalizeCondition(cond) {
  let s = "";
  if (typeof cond === "string") s = cond;
  else if (cond && typeof cond === "object") s = cond.main || cond.description || "";
  s = String(s).toLowerCase();

  if (!s) return "clear"; // fallback

  if (s.includes("thunder")) return "thunder";
  if (s.includes("drizzle") || s.includes("rain")) return "rain";
  if (s.includes("snow")) return "snow";
  if (s.includes("cloud")) return "cloudy";
  if (s.includes("mist") || s.includes("fog") || s.includes("haze") || s.includes("smoke"))
    return "fog";
  if (s.includes("tornado") || s.includes("squall")) return "thunder";
  // default
  return "clear";
}

// Map [condition][isDay? "day":"night"][device] -> file
const VIDEO_MAP = {
  clear: {
    day:   { desktop: clearDayDesktop,   mobile: clearDayMobile },
    night: { desktop: clearNightDesktop, mobile: clearNightMobile },
  },
  cloudy: {
    day:   { desktop: cloudyDayDesktop,   mobile: cloudyDayMobile },
    night: { desktop: cloudyNightDesktop, mobile: cloudyNightMobile },
  },
  rain: {
    day:   { desktop: rainDayDesktop,   mobile: rainDayMobile },
    night: { desktop: rainNightDesktop, mobile: rainNightMobile },
  },
  snow: {
    day:   { desktop: snowDayDesktop,   mobile: snowDayMobile },
    night: { desktop: snowNightDesktop, mobile: snowNightMobile },
  },
  thunder: {
    day:   { desktop: thunderDayDesktop,   mobile: thunderDayMobile },
    night: { desktop: thunderNightDesktop, mobile: thunderNightMobile },
  },
  fog: {
    day:   { desktop: fogDayDesktop,   mobile: fogDayMobile },
    night: { desktop: fogNightDesktop, mobile: fogNightMobile },
  },
};

export default function WeatherOverlay({
  condition,        // string or object ({main, description,...})
  isDay = true,     // boolean
  device = "desktop", // "desktop" | "mobile"
  className = "",
  opacity = 0.8,    // tweak if you want the video lighter/darker
}) {
  const key = useMemo(() => normalizeCondition(condition), [condition]);
  const dayKey = isDay ? "day" : "night";
  const devKey = device === "mobile" ? "mobile" : "desktop";

  const src = VIDEO_MAP[key]?.[dayKey]?.[devKey];

  // If no matching video, fail safe to nothing (no overlay) rather than throwing.
  if (!src) return null;

  return (
    <div
      className={`fixed inset-0 -z-10 pointer-events-none ${className}`}
      aria-hidden="true"
    >
      <video
        src={src}
        autoPlay
        muted
        loop
        playsInline
        // Cover full viewport, behind UI
        className="w-full h-full object-cover"
        style={{ opacity }}
      />
    </div>
  );
}
